def solve(s: str) -> str:
    result = []
    for char in s:
        if char.isalpha():
            result.append(char)
        elif char == '*':
            if result:
                result.pop()
        elif char == '#':
            result.extend(result.copy())
        elif char == '%':
            result = result[::-1]
    return ''.join(result)
